            quantity: 1,
            duration: 4,
            unit_price: 100,
            monthly_payment: 25,
            total_price: 100
          }, {
            id: 2,
            product_name: 'Produit B',
            product_reference: 'REF456',
            quantity: 2,
            duration: 4,
            unit_price: 100,
