            total_price: 200
          }]
        };
        quote.value = quoteData;
        quoteItems.value = quoteData.items;

        // Simulated data for history
        history.value = [{
          id: 1,
          action: 'Créé',
          description: 'Le devis a été créé.',
          created_at: '2023-10-01T12:00:00Z'
        }, {
          id: 2,
          action: 'Mis à jour',
          description: 'Le devis a été mis à jour.',
          created_at: '2023-10-02T14:00:00Z'
        }];
      } catch (e) {
        error.value = e.message;
